aterController;\n}>();\n\nconst snapshot = shallowRef<UpdaterSnapshot>(props.updater.getSnapshot());\nconst isBusy = computed(() => snapshot.value.status === 'checking' || snapshot.value.status === 'installing');\n\nlet unsubscribe: (() => void) | undefined;\n\nonMounted(() => {\n  unsubscribe = props.updater.subscribe(value => {\n    snapshot.value = value;\n  });\n});\n\nonUnmounted(() => {\n  unsubscribe?.();\n});\n\nasync function checkForUpdates() {\n  try {\n    await props.updater.check();\n  } catch {\n    // 错误已经写入更新器快照，由面板统一显示。\n  }\n}\n\nasync function installUpdate() {\n  const latestVersion = snapshot.value.latestVersion;\n  if (!latestVersion) {\n    return;\n  }\n\n  const confirmed = await SillyTavern.callGenericPopup(\n    `确定将${props.updater.pluginName}更新至 v${latestVersion} 吗？`,\n    SillyTavern.POPUP_TYPE.CONFIRM,\n  );\n  if (confirmed !== true && confirmed !== SillyTavern.POPUP_RESULT.AFFIRMATIVE) {\n    return;\n  }\n\n  try {\n    await props.updater.install();\n  } catch {\n    // 错误已经写入更新器快照，由面板统一显示。\n  }\n}\n</script>\n\n<style scoped>\n.th-updater-panel {\n  display: grid;\n  grid-template-columns: minmax(0, 1fr) auto;\n  align-items: center;\n  gap: 0.4rem 0.65rem;\n  padding: 0.65rem 0;\n  border-top: 1px solid var(--SmartThemeBorderColor);\n}\n\n.th-updater-summary,\n.th-updater-actions {\n  display: flex;\n  align-items: center;\n  gap: 0.45rem;\n  min-width: 0;\n}\n\n.th-updater-version {\n  font-variant-numeric: tabular-nums;\n  white-space: nowrap;\n}\n\n.th-updater-latest,\n.th-updater-current {\n  overflow: hidden;\n  opacity: 0.75;\n  font-size: 0.9em;\n  text-overflow: ellipsis;\n  white-space: nowrap;\n}\n\n.th-updater-actions .menu_button {\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  flex: 0 0 auto;\n  min-width: 2em;\n  height: 2em;\n  margin: 0;\n  padding: 0 0.55rem;\n}\n\n.th-updater-error {\n  grid-column: 1 / -1;\n  color: var(--crimson70, #d66);\n  overflow-wrap: anywhere;\n}\n\n@media (max-width: 600px) {\n  .th-updater-panel {\n    grid-template-columns: minmax(0, 1fr);\n  }\n\n  .th-updater-actions {\n    justify-content: flex-end;\n  }\n}\n</style>\n"],"sourceRoot":""}]);
